// Code Node: SHA-256 Fingerprinting & Metadata Extraction
const crypto = require('crypto');
const items = $input.all();

return items.map(item => {
    const binary = item.binary.data;
    const buffer = Buffer.from(binary.data, 'base64');

    // Generate forensic hash
    item.json.originalHash = crypto.createHash('sha256').update(buffer).digest('hex');

    // Create custody ID with timestamp
    const timestamp = new Date().toISOString().replace(/[-:]/g, '').split('.')[0];
    item.json.custodyID = `DISCOVERY-${timestamp}-${Math.random().toString(36).substring(2, 8).toUpperCase()}`;

    // Extract metadata
    item.json.fileSize = buffer.length;
    item.json.intakeTimestamp = new Date().toISOString();
    item.json.mimeType = binary.mimeType || 'application/pdf';
    item.json.fileName = item.json.name || 'unknown.pdf';
    item.json.processingStatus = 'INTAKE_COMPLETE';

    return item;
});

// Code Node: Post-Unlock Integrity Validation
const item = $input.first();
const crypto = require('crypto');

try {
    const buffer = Buffer.from(item.binary.data.data, 'base64');

    // Generate hash of unlocked file
    item.json.unlockedHash = crypto.createHash('sha256').update(buffer).digest('hex');
    item.json.unlockedSize = buffer.length;
    item.json.unlockTimestamp = new Date().toISOString();

    // Verify unlock was successful (hashes should differ)
    if (item.json.originalHash === item.json.unlockedHash) {
        item.json.integrityStatus = 'WARNING: Hashes identical - possible unlock failure';
        item.json.processingStatus = 'UNLOCK_SUSPICIOUS';
    } else {
        item.json.integrityStatus = 'VERIFIED: File successfully decrypted';
        item.json.processingStatus = 'UNLOCK_SUCCESS';
    }

    // Calculate processing time
    const intakeTime = new Date(item.json.intakeTimestamp);
    const unlockTime = new Date(item.json.unlockTimestamp);
    item.json.processingTimeMs = unlockTime - intakeTime;

} catch (error) {
    item.json.integrityStatus = `ERROR: ${error.message}`;
    item.json.processingStatus = 'UNLOCK_FAILED';
}

return item;

